import java.util.*;class SinglyStudent{static class N{int r,a;String n,g;N next;N(int r,String n,int a,String g){this.r=r;this.n=n;this.a=a;this.g=g;}}static N head;static void add(int r,String n,int a,String g){N t=new N(r,n,a,g);t.next=head;head=t;}static void display(){N c=head;while(c!=null){System.out.println(c.r+" "+c.n+" "+c.a+" "+c.g);c=c.next;}}public static void main(String[] a){add(1,"A",20,"A");add(2,"B",21,"B");display();}}